module div_16bit
(
    input [15:0] A,
    input [7:0] B,
    output [15:0] result,
    output [15:0] odd
);
    reg [15:0] a_reg, b_reg;
    reg [15:0] result_reg, odd_reg;

    always @(A, B) begin
        a_reg = A;
        b_reg = B;
    end

    always @(a_reg, b_reg) begin
        result_reg = 0;
        odd_reg = a_reg;

        for (int i = 0; i < 16; i = i + 1) begin
            if (odd_reg[15:8] >= b_reg) begin
                result_reg[i] = 1;
                odd_reg = {odd_reg[14:0], a_reg[15-i]};
            end else begin
                result_reg[i] = 0;
                odd_reg = {odd_reg[14:0], a_reg[15-i]};
            end
        end
    end

    assign result = result_reg;
    assign odd = odd_reg;
endmodule
